# Utility module with constants and helper functions

# Module constants
const PI: float = 3.14159
const EULER: float = 2.71828

# Helper class for calculations
class Calculator:
    _sum: float
    _count: int

    def __init__(self):
        self._sum = 0.0
        self._count = 0

    @virtual
    def add(self, value: float) -> float:
        self._sum = self._sum + value
        self._count = self._count + 1
        return self._sum

    @virtual
    def average(self) -> float:
        if self._count == 0:
            return 0.0
        return self._sum / float(self._count)

    @virtual
    def count(self) -> int:
        return self._count

def square(x: float) -> float:
    return x * x

def double(x: float) -> float:
    return x * 2.0
